// Build lookup maps
const POKEMON_MAP = {};
const POKEMON_BY_ID = {};
POKEMON_DB.forEach(p => {
    const obj = {
        id: p[0], name: p[1], types: p[2],
        stats: [
            { base_stat: p[3][0], stat: { name: 'hp' } },
            { base_stat: p[3][1], stat: { name: 'attack' } },
            { base_stat: p[3][2], stat: { name: 'defense' } },
            { base_stat: p[3][3], stat: { name: 'special-attack' } },
            { base_stat: p[3][4], stat: { name: 'special-defense' } },
            { base_stat: p[3][5], stat: { name: 'speed' } }
        ],
        height: p[4] * 10, weight: p[5] * 10,
        abilities: p[6].map(a => ({ ability: { name: a } })),
        types_full: p[2].map((t, i) => ({ slot: i + 1, type: { name: t } })),
        base_experience: Math.round(p[3].reduce((a, b) => a + b, 0) / 2),
        moves: [],
        sprites: {},
        flavor_text: p[7]
    };
    POKEMON_MAP[p[1]] = obj;
    POKEMON_BY_ID[p[0]] = obj;
});

